def extract_removed_lines(diff_text: str) -> List[str]:
    """Extract all lines that start with '-' (removed lines), excluding diff headers."""
    removed_lines = []
    for line in diff_text.split('\n'):
        # Skip diff header lines (e.g., '--- a/file.ts')
        if line.startswith('-') and not line.startswith('---'):
            removed_lines.append(line[1:])  # Remove the '-' prefix
    return removed_lines


def extract_added_lines(diff_text: str) -> List[str]:
    """Extract all lines that start with '+' (added lines), excluding diff headers."""
    added_lines = []
    for line in diff_text.split('\n'):
        # Skip diff header lines (e.g., '+++ b/file.ts')
        if line.startswith('+') and not line.startswith('+++'):
            added_lines.append(line[1:])  # Remove the '+' prefix
    return added_lines


def extract_function_definitions(lines: List[str]) -> Set[str]:
    """
    Extract function/method names from lines.
    Handles various patterns:
    - TypeScript/JavaScript: function name(, async function name(
    - Method calls that are being assigned: const x = await functionName({
    - Import statements: import { functionName }
    - Method names: .methodName(
    """
    function_names = set()

    # Pattern for function definitions
    func_def_pattern = r'(?:function|async\s+function)\s+(\w+)\s*\('

    # Pattern for method calls in the form: await functionName({
    method_call_pattern = r'await\s+(\w+)\s*\('

    # Pattern for imports: import { name1, name2 }
    import_pattern = r'import\s*\{([^}]+)\}'

    # Pattern for method chaining: .methodName(
    chained_method_pattern = r'\.(\w+)\s*\('

    for line in lines:
        # Find function definitions
        for match in re.finditer(func_def_pattern, line):
            function_names.add(match.group(1))

        # Find method calls
        for match in re.finditer(method_call_pattern, line):
            function_names.add(match.group(1))

        # Find imported names
        for match in re.finditer(import_pattern, line):
            imports = match.group(1)
            for name in imports.split(','):
                cleaned = name.strip()
                if cleaned:
                    function_names.add(cleaned)

        # Find chained methods
        for match in re.finditer(chained_method_pattern, line):
            function_names.add(match.group(1))

    return function_names


def analyze_diff(diff_text: str) -> Tuple[Set[str], Set[str], Set[str]]:
    """
    Analyze a diff to find:
    1. Function names that were removed
    2. Function names that were added
    3. Function names removed but NOT re-added (potential bugs!)

    Returns tuple: (removed_functions, added_functions, potentially_broken_functions)
    """
    removed_lines = extract_removed_lines(diff_text)
    added_lines = extract_added_lines(diff_text)

    removed_functions = extract_function_definitions(removed_lines)
    added_functions = extract_function_definitions(added_lines)

    # Find functions that were removed but NOT added back (potential bugs)
    potentially_broken = removed_functions - added_functions

    return removed_functions, added_functions, potentially_broken
